SELECT COUNT(*) AS TOTAL FROM LATTES_P_PRODTEC LP JOIN LATTES_PRODTEC PT ON PT.PK = LP.FK_PRODTEC JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('uru') AND LOWER(COALESCE(S.AREA_INGRESSO, S.AREA_INGRESSO_OG, '')) LIKE '%letras%' AND LOWER(COALESCE(PT.NATUREZA, '')) = 'organizacao' AND PT.ANO >= CAST(CAST(strftime('%Y', 'now') AS INTEGER) AS INTEGER) - 4